@dataclass(frozen=True)
class RunOutput:
    returncode: int
    stdout: str
    stderr: str = ""
    exc: Exception | None = None

    @classmethod
    def timeout(cls, seconds: int):
        return cls(returncode=-1, stdout=f"Process timeout after {seconds} second(s)")

    def formatted(self) -> str:
        return f"<returncode>{self.returncode}</returncode>\n<stdout>{self.stdout}</stdout>\n<stderr>{self.stderr}</stderr>"


@dataclass(frozen=True)
class Project:
    root: Path

    def __post_init__(self) -> None:
        timestamp = datetime.now().isoformat().replace(":", "-")
        self.agent_log_path = self.root / ".tim" / "agent-logs" / f"{timestamp}-{os.getpid()}.jsonl"

    @classmethod
    def cwd(cls) -> "Project":
        return cls(Path.cwd())

    def run(self, command: str, timeout: int = 1) -> RunOutput:
        raise NotImplementedError()

    def path(self, path: str | Path) -> Path:
        return (self.root / path).resolve()

    def _write_agent_log(self, logline: dict):
        self.agent_log_path.parent.mkdir(parents=True, exist_ok=True)
        with open(self.agent_log_path, "a", encoding="utf-8") as out:
            out.write(json.dumps(logline))
            out.write("\n")

    def agent_log(self, agent, message, prompt_tokens=None, completion_tokens=None):
        logline = AgentMessage(
            agent=agent.__class__.__name__,
            agent_instance=id(agent),
            timestamp=datetime.now(timezone.utc),
            **_message_to_agent_message(message),
            usage_prompt_tokens=prompt_tokens,
            usage_completion_tokens=completion_tokens,
        ).to_dict()
        self._write_agent_log(logline)


def _message_to_agent_message(message) -> dict:
    """Convert a message (dict or object) to keyword arguments for AgentMessage."""
    if isinstance(message, dict):
        role = message["role"]
        content = message.get("content")
        reasoning = message.get("reasoning")
        tool_id = message.get("tool_call_id") or message.get("id")
        tool_calls_raw = message.get("tool_calls", [])
        tool_calls = []
        for tc in tool_calls_raw:
            if isinstance(tc, ToolCall):
                tool_calls.append(tc)
            elif isinstance(tc, dict):
                tool_calls.append(ToolCall(
                    id=tc["id"],
                    name=tc["name"],
                    arguments=tc["arguments"],
                ))
            else:
                tool_calls.append(ToolCall(
                    id=tc.id,
                    name=tc.function.name,
                    arguments=tc.function.arguments,
                ))
    else:
        role = message.role
        content = message.content
        reasoning = getattr(message, "reasoning_content", None) or getattr(message, "reasoning", None)
        tool_id = getattr(message, "tool_call_id", None) or getattr(message, "id", None)
        tool_calls_raw = getattr(message, "tool_calls", None) or []
        tool_calls = []
        for tc in tool_calls_raw:
            if isinstance(tc, ToolCall):
                tool_calls.append(tc)
            elif isinstance(tc, dict):
                tool_calls.append(ToolCall(
                    id=tc["id"],
                    name=tc["name"],
                    arguments=tc["arguments"],
                ))
            else:
                tool_calls.append(ToolCall(
                    id=tc.id,
                    name=tc.function.name,
                    arguments=tc.function.arguments,
                ))

    result: dict = {"role": role}
    if content is not None:
        result["content"] = content
    if reasoning is not None:
        result["reasoning"] = reasoning
    if tool_calls:
        result["tool_calls"] = tool_calls
    if tool_id is not None:
        result["tool_id"] = tool_id
    return result


